import{_ as a,o as n,c as l,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Create & Manage Alliances","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/manage-alliances.md","filePath":"how-to/manage-alliances.md"}'),t={name:"how-to/manage-alliances.md"};function o(r,e,s,c,d,h){return n(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="create-manage-alliances" tabindex="-1">Create &amp; Manage Alliances <a class="header-anchor" href="#create-manage-alliances" aria-label="Permalink to &quot;Create &amp; Manage Alliances&quot;">​</a></h1><p>An alliance lives inside a kingdom. Use alliance management when you need to add a new alliance, rename one, review who is responsible for it, or inspect its players, imports, and reports.</p><blockquote><p>Screenshot placeholder: alliance-detail.png</p></blockquote><h2 id="create-an-alliance" tabindex="-1">Create an alliance <a class="header-anchor" href="#create-an-alliance" aria-label="Permalink to &quot;Create an alliance&quot;">​</a></h2><p>The normal place to create one is the kingdom page.</p><ol><li>Open the kingdom.</li><li>Find <strong>Add Alliance</strong>.</li><li>Enter the <strong>Alliance name</strong> and <strong>Alliance tag</strong>.</li><li>Select <strong>Create alliance</strong>.</li></ol><h2 id="open-the-alliance-page" tabindex="-1">Open the alliance page <a class="header-anchor" href="#open-the-alliance-page" aria-label="Permalink to &quot;Open the alliance page&quot;">​</a></h2><p>From the kingdom page, select <strong>Open</strong> beside the alliance you want.</p><p>The alliance detail page is the admin-facing version of alliance management. It is mainly for <code>Supreme Admin</code> and <code>King</code> users. <code>Alliance Leader</code> and <code>Co-Leader</code> use <strong>My Alliance</strong> instead.</p><h2 id="what-you-can-do-on-the-alliance-page" tabindex="-1">What you can do on the alliance page <a class="header-anchor" href="#what-you-can-do-on-the-alliance-page" aria-label="Permalink to &quot;What you can do on the alliance page&quot;">​</a></h2><ul><li>rename the alliance</li><li>review player counts and API-linked counts</li><li>review responsible users</li><li>open player profiles</li><li>review recent imports</li><li>review recent reports</li><li>delete the alliance when policy allows it</li></ul><h2 id="subscription-note-for-alliance-pages" tabindex="-1">Subscription note for alliance pages <a class="header-anchor" href="#subscription-note-for-alliance-pages" aria-label="Permalink to &quot;Subscription note for alliance pages&quot;">​</a></h2><p>You may see usage or premium information here too. The important short version is:</p><ul><li>paid access does not flow down automatically just because the parent kingdom has a paid plan</li><li>an alliance gets paid benefits from its own direct subscription or from an accepted grant</li><li>grant limits depend on the kingdom&#39;s current plan, so they are not fixed forever</li></ul><p>This batch does not explain subscription rules in depth. That comes later in the subscriptions section.</p><h2 id="when-to-use-this-page-instead-of-my-alliance" tabindex="-1">When to use this page instead of My Alliance <a class="header-anchor" href="#when-to-use-this-page-instead-of-my-alliance" aria-label="Permalink to &quot;When to use this page instead of My Alliance&quot;">​</a></h2><p>Use the alliance admin page when you are acting as a <code>Supreme Admin</code> or <code>King</code>. Use <a href="./my-alliance.html">Use the My Alliance Page</a> when you are acting as an <code>Alliance Leader</code> or <code>Co-Leader</code>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./manage-kingdoms.html">Create &amp; Manage Kingdoms</a></li><li><a href="./my-alliance.html">Use the My Alliance Page</a></li><li><a href="./../reference/alliance-membership.html">How Alliance Membership Works</a></li><li><a href="./kick-player.html">Kick a Player from the Alliance</a></li></ul>',19)])])}const g=a(t,[["render",o]]);export{m as __pageData,g as default};
